    @Configuration
    public static class ElasticsearchConfig {

        @Value("${elasticsearch.host}")
        private String host;

        @Value("${elasticsearch.port}")
        private int port;

        @Value("${elasticsearch.username}")
        private String username;

        @Value("${elasticsearch.password}")
        private String password;

        @Bean
        public RestHighLevelClient restHighLevelClient() throws Exception {
            SSLContext sslContext = SSLContext.getInstance("TLS");
            sslContext.init(null, new TrustManager[]{new X509TrustManager() {
                public void checkClientTrusted(X509Certificate[] chain, String authType) {}
                public void checkServerTrusted(X509Certificate[] chain, String authType) {}
                public X509Certificate[] getAcceptedIssuers() { return new X509Certificate[0]; }
            }}, new java.security.SecureRandom());

            return new RestHighLevelClient(
                org.elasticsearch.client.RestClient.builder(
                    new HttpHost(host, port, "https"))
                    .setHttpClientConfigCallback(httpClientBuilder -> {
                        httpClientBuilder.setSSLContext(sslContext);
                        return httpClientBuilder;
                    })
            );
        }
    }

    @RestController
    @RequestMapping("/api/search")
    public class SearchController {

        @Autowired
        private RestHighLevelClient client;

        @Autowired
        private ElasticsearchRestTemplate elasticsearchTemplate;

        @PostMapping("/index")
        public ResponseEntity<String> indexProducts(@RequestBody List<Product> products) throws IOException {
            BulkRequest bulkRequest = new BulkRequest();
            for (Product product : products) {
                IndexRequest request = new IndexRequest("products")
                        .id(product.getId())
                        .source(product.toJson(), XContentType.JSON);
                bulkRequest.add(request);
            }
            BulkResponse response = client.bulk(bulkRequest, RequestOptions.DEFAULT);
            return ResponseEntity.ok("Indexed " + response.getItems().length + " products");
        }

        @GetMapping("/search")
        public ResponseEntity<List<Product>> searchProducts(
                @RequestParam(required = false) String query,
                @RequestParam(required = false) List<String> categories,
                @RequestParam(required = false) Double minPrice,
                @RequestParam(required = false) Double maxPrice,
                @RequestParam(defaultValue = "0") int from,
                @RequestParam(defaultValue = "20") int size) throws IOException {

            SearchRequest searchRequest = new SearchRequest("products");
            SearchSourceBuilder searchSourceBuilder = new SearchSourceBuilder();
            BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

            if (query != null && !query.isEmpty()) {
                boolQuery.must(QueryBuilders.multiMatchQuery(query, "name", "description")
                        .type(MultiMatchQueryBuilder.Type.BEST_FIELDS));
            }

            if (categories != null && !categories.isEmpty()) {
                boolQuery.filter(QueryBuilders.termsQuery("categories", categories));
            }

            if (minPrice != null) {
                boolQuery.filter(QueryBuilders.rangeQuery("price").gte(minPrice));
            }

            if (maxPrice != null) {
                boolQuery.filter(QueryBuilders.rangeQuery("price").lte(maxPrice));
            }

            searchSourceBuilder.query(boolQuery);
            searchSourceBuilder.from(from);
            searchSourceBuilder.size(size);

            HighlightBuilder highlightBuilder = new HighlightBuilder();
            highlightBuilder.field("name");
            highlightBuilder.field("description");
            highlightBuilder.preTags("<em>");
            highlightBuilder.postTags("</em>");
            searchSourceBuilder.highlighter(highlightBuilder);

            searchRequest.source(searchSourceBuilder);

            SearchResponse searchResponse = client.search(searchRequest, RequestOptions.DEFAULT);
            List<Product> results = new ArrayList<>();
            for (SearchHit hit : searchResponse.getHits()) {
                Product product = Product.fromJson(hit.getSourceAsString());
                product.setScore(hit.getScore());
                results.add(product);
            }

            return ResponseEntity.ok(results);
        }

        @GetMapping("/facets")
        public ResponseEntity<Map<String, Object>> getFacets(
                @RequestParam(required = false) String query,
                @RequestParam(required = false) List<String> categories,
                @RequestParam(required = false) Double minPrice,
                @RequestParam(required = false) Double maxPrice) throws IOException {

            SearchRequest searchRequest = new SearchRequest("products");
            SearchSourceBuilder searchSourceBuilder = new SearchSourceBuilder();
            BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

            if (query != null && !query.isEmpty()) {
                boolQuery.must(QueryBuilders.multiMatchQuery(query, "name", "description"));
            }

            if (categories != null && !categories.isEmpty()) {
                boolQuery.filter(QueryBuilders.termsQuery("categories", categories));
            }

            if (minPrice != null) {
                boolQuery.filter(QueryBuilders.rangeQuery("price").gte(minPrice));
            }

            if (maxPrice != null) {
                boolQuery.filter(QueryBuilders.rangeQuery("price").lte(maxPrice));
            }

            searchSourceBuilder.query(boolQuery);
            searchSourceBuilder.size(0);

            searchSourceBuilder.aggregation(AggregationBuilders.terms("categories").field("categories"));
            searchSourceBuilder.aggregation(AggregationBuilders.range("price_ranges").field("price")
                    .addRange("0-50", 0, 50)
                    .addRange("50-100", 50, 100)
                    .addRange("100-200", 100, 200)
                    .addRange("200+", 200, Double.MAX_VALUE));

            searchRequest.source(searchSourceBuilder);

            SearchResponse searchResponse = client.search(searchRequest, RequestOptions.DEFAULT);
            Map<String, Object> facets = new HashMap<>();

            facets.put("categories", searchResponse.getAggregations().get("categories"));
            facets.put("price_ranges", searchResponse.getAggregations().get("price_ranges"));

            return ResponseEntity.ok(facets);
        }

        @PostMapping("/query")
        public ResponseEntity<String> saveQuery(@RequestBody SearchQuery query) throws IOException {
            IndexRequest request = new IndexRequest("search_queries")
                    .id(UUID.randomUUID().toString())
                    .source(query.toJson(), XContentType.JSON);
            client.index(request, RequestOptions.DEFAULT);
            return ResponseEntity.ok("Query saved");
        }

        @GetMapping("/suggestions")
        public ResponseEntity<List<String>> getSuggestions(@RequestParam String prefix) throws IOException {
            SearchRequest searchRequest = new SearchRequest("products");
            SearchSourceBuilder searchSourceBuilder = new SearchSourceBuilder();

            CompletionSuggestionBuilder suggestionBuilder = SuggestBuilders.completionSuggestion("name_suggest")
                    .prefix(prefix)
                    .size(10);

            SuggestBuilder suggestBuilder = new SuggestBuilder();
            suggestBuilder.addSuggestion("product_suggestions", suggestionBuilder);

            searchSourceBuilder.suggest(suggestBuilder);
            searchRequest.source(searchSourceBuilder);

            SearchResponse searchResponse = client.search(searchRequest, RequestOptions.DEFAULT);
            List<String> suggestions = new ArrayList<>();

            searchResponse.getSuggest().forEach(suggestion -> {
                suggestion.forEach(item -> {
                    item.forEach(option -> suggestions.add(option.getText().string()));
                });
            });

            return ResponseEntity.ok(suggestions);
        }
    }

    @PostConstruct
    public void createIndices() throws IOException {
        CreateIndexRequest request = new CreateIndexRequest("products");
        request.settings(Settings.builder()
                .put("index.number_of_shards", 1)
                .put("index.number_of_replicas", 1)
                .put("index.refresh_interval", "30s")
        );

        request.mapping(
                "{\n" +
                "  \"properties\": {\n" +
                "    \"id\": {\"type\": \"keyword\"},\n" +
                "    \"name\": {\n" +
                "      \"type\": \"text\",\n" +
                "      \"analyzer\": \"standard\",\n" +
                "      \"fields\": {\n" +
                "        \"keyword\": {\"type\": \"keyword\"}\n" +
                "      }\n" +
                "    },\n" +
                "    \"description\": {\n" +
                "      \"type\": \"text\",\n" +
                "      \"analyzer\": \"standard\"\n" +
                "    },\n" +
                "    \"price\": {\"type\": \"float\"},\n" +
                "    \"categories\": {\"type\": \"keyword\"},\n" +
                "    \"tags\": {\"type\": \"keyword\"},\n" +
                "    \"name_suggest\": {\n" +
                "      \"type\": \"completion\",\n" +
                "      \"analyzer\": \"simple\"\n" +
                "    }\n" +
                "  }\n" +
                "}", XContentType.JSON);

        GetIndexRequest getIndexRequest = new GetIndexRequest("products");
        if (!client.indices().exists(getIndexRequest, RequestOptions.DEFAULT)) {
            client.indices().create(request, RequestOptions.DEFAULT);
        }

        CreateIndexRequest queryRequest = new CreateIndexRequest("search_queries");
        queryRequest.settings(Settings.builder()
                .put("index.number_of_shards", 1)
                .put("index.number_of_replicas", 1)
        );

        queryRequest.mapping(
                "{\n" +
                "  \"properties\": {\n" +
                "    \"query\": {\"type\": \"text\"},\n" +
                "    \"timestamp\": {\"type\": \"date\"},\n" +
                "    \"user_id\": {\"type\": \"keyword\"}\n" +
                "  }\n" +
                "}", XContentType.JSON);

        GetIndexRequest getQueryIndexRequest = new GetIndexRequest("search_queries");
        if (!client.indices().exists(getQueryIndexRequest, RequestOptions.DEFAULT)) {
            client.indices().create(queryRequest, RequestOptions.DEFAULT);
        }
    }
